import './Skeleton.css';

/**
 * Skeleton Component with Shimmer Animation
 * 
 * A reusable skeleton component with shimmer effects for loading states.
 * Supports multiple shape variants and proper typing for prop definitions.
 */
const Skeleton = ({ width = '100%', height = 'auto', variant = 'default' }) => {
  const getShimmerStyle = (variant) => {
    switch (variant) {
      case 'grid':
        return {
          background: `
            linear-gradient(90deg, 
              #e5e7eb 1px, transparent 1px),
            linear-gradient(rgba(255, 255, 255, 0.1) 1px, transparent 1px)
          `,
          backgroundSize: `${width} ${width}`,
        };
      case 'circle':
        return {
          background: `
            radial-gradient(
              circle at top left, 
              rgba(255, 255, 255, 0.1) 40%, 
              transparent 60%
            )
          `,
          borderRadius: '50%',
        };
      case 'line':
        return {
          background: `
            linear-gradient(90deg, 
              #e5e7eb ${width}px, 
              transparent ${width}px)
          `,
        };
      default:
        return {
          background: '#e5e7eb',
          borderRadius: '4px',
        };
    }
  };

  const getShape = (variant) => {
    switch (variant) {
      case 'grid':
        return (
          <div className="skeleton-grid" style={getShimmerStyle(variant)}>
            {[...Array(4)].map((_, i) => (
              <div key={i} className="skeleton-row" style={{ width: `${width}%` }} />
            ))}
          </div>
        );
      case 'circle':
        return (
          <div className="skeleton-circle" style={getShimmerStyle(variant)}>
            {[...Array(8)].map((_, i) => (
              <div key={i} className="skeleton-segment" style={{ width: `${Math.random() * 100}%` }} />
            ))}
          </div>
        );
      case 'line':
        return (
          <div className="skeleton-line" style={getShimmerStyle(variant)}>
            {[...Array(3)].map((_, i) => (
              <div key={i} className="skeleton-bar" style={{ height: `${height}px` }} />
            ))}
          </div>
        );
      default:
        return (
          <div className="skeleton-box" style={getShimmerStyle(variant)} />
        );
    }
  };

  const variants = {
    default: 'grid',
    circle: 'circle',
    line: 'line',
  };

  return (
    <div className={`skeleton skeleton-${variants[variant]}`} style={{ width, height }}>
      {getShape(variant)}
    </div>
  );
};

/**
 * Suspense boundary for lazy loading with Skeleton
 */
const SkeletonLoader = ({ children }) => {
  const [isLoaded, setIsLoaded] = React.useState(false);

  if (!isLoaded) {
    return <Suspense fallback={<Skeleton />}>{children}</Suspense>;
  }

  return <>{children}</>;
};

export default Skeleton;
