.skeleton {
  background-color: #f3f4f6;
  border-radius: 8px;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
}

/* Grid Variant (Table-like Skeleton) */
.skeleton-grid .skeleton-row {
  background-color: #d1d5db;
  border-radius: 2px;
  height: 4px;
  margin-top: 8px;
  box-sizing: border-box;
}

/* Circle Variant (Circular Skeleton) */
.skeleton-circle .skeleton-segment {
  background-color: #d1d5db;
  border-radius: 9999px;
  height: 4px;
  margin-top: 8px;
  box-sizing: border-box;
}

/* Line Variant (Linear Skeleton) */
.skeleton-line .skeleton-bar {
  background-color: #d1d5db;
  height: 100%;
  width: 20px;
  margin-right: 4px;
  box-sizing: border-box;
}

/* Box Variant (Card Skeleton) */
.skeleton-box .skeleton-row {
  background-color: #d1d5db;
  border-radius: 4px;
  height: 20px;
  margin-top: 8px;
  box-sizing: border-box;
}

/* Shimmer Animation Keyframes */
@keyframes shimmerGrid {
  0% { background-position: -200% center; }
  100% { background-position: 200% center; }
}

@keyframes shimmerCircle {
  0% { background-position: -50% top left; }
  100% { background-position: 50% top right; }
}

@keyframes shimmerLine {
  0% { background-position: -200% center; }
  100% { background-position: 200% center; }
}

@keyframes shimmerBox {
  0% { background-position: -200% center; }
  100% { background-position: 200% center; }
}

/* Shimmer Animation Classes */
.skeleton-grid:hover .skeleton-row,
.skeleton-grid:focus-within .skeleton-row,
.skeleton-circle:hover .skeleton-segment,
.skeleton-circle:focus-within .skeleton-segment,
.skeleton-line:hover .skeleton-bar,
.skeleton-line:focus-within .skeleton-bar,
.skeleton-box:hover .skeleton-row,
.skeleton-box:focus-within .skeleton-row {
  animation: shimmerGrid 1.5s infinite linear;
}

.skeleton-grid:hover .skeleton-circle,
.skeleton-grid:focus-within .skeleton-circle,
.skeleton-circle:hover .skeleton-line,
.skeleton-circle:focus-within .skeleton-line,
.skeleton-box:hover .skeleton-grid,
.skeleton-box:focus-within .skeleton-grid {
  animation: shimmerCircle 1.5s infinite linear;
}

.skeleton-grid:hover .skeleton-line,
.skeleton-grid:focus-within .skeleton-line,
.skeleton-line:hover .skeleton-circle,
.skeleton-line:focus-within .skeleton-circle,
.skeleton-box:hover .skeleton-circle,
.skeleton-box:focus-within .skeleton-circle {
  animation: shimmerLine 1.5s infinite linear;
}

/* Hover Effect for Interactive Elements */
.skeleton:hover,
.skeleton:focus-within {
  cursor: default;
}

/* Reduced Motion Preference */
@media (prefers-reduced-motion: reduce) {
  .skeleton-grid:hover .skeleton-row,
  .skeleton-circle:hover .skeleton-segment,
  .skeleton-line:hover .skeleton-bar,
  .skeleton-box:hover .skeleton-row,
  .skeleton-box:focus-within .skeleton-row {
    animation: none;
  }
}
