/* Scoped to prevent leaks using unique ID-based scoping */

/* Base skeleton container with shimmer effect */
.skeleton {
  position: relative;
  overflow: hidden;
}

/* Main skeleton animation keyframes */
@keyframes shimmer {
  0% {
    background-position: -200% 0;
  }
  100% {
    background-position: 200% 0;
  }
}

/* Fast shimmer variant (high animation frequency) */
.skeleton.fast {
  animation-name: shimmer;
  animation-duration: 0.6s;
  animation-timing-function: linear;
  animation-fill-mode: forwards;
}

/* Normal/shimmer variant (default speed) */
.skeleton.normal {
  animation-name: shimmer;
  animation-duration: 1.5s;
  animation-timing-function: ease-in-out;
  animation-fill-mode: forwards;
}

/* Slow shimmer variant (low animation frequency) */
.skeleton.slow {
  animation-name: shimmer;
  animation-duration: 3s;
  animation-timing-function: ease-in-out;
  animation-fill-mode: forwards;
}

/* Shimmer effect variants for different elements */
/* Text skeleton - fills the text with shimmering gradient */
.skeleton-text {
  background-image: linear-gradient(
    45deg,
    rgba(255, 255, 255, 0) 25%,
    rgba(255, 255, 255, 0.15) 50%,
    rgba(255, 255, 255, 0) 75%
  );
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite linear;
}

/* Input field skeleton - borders with shimmering effect */
.skeleton-input {
  height: 3px;
  background-image: linear-gradient(90deg, transparent 25%, rgba(255, 255, 255, 0.15) 50%, transparent 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite linear;
}

/* Button skeleton - rounded rectangle with shimmering border */
.skeleton-button {
  height: 3px;
  border-radius: 4px;
  background-image: linear-gradient(90deg, transparent 25%, rgba(255, 255, 255, 0.15) 50%, transparent 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite linear;
}

/* Card skeleton - box with inner elements */
.skeleton-card {
  height: 3px;
  background-image: linear-gradient(90deg, transparent 25%, rgba(255, 255, 255, 0.15) 50%, transparent 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite linear;
}

/* List item skeleton - border with shimmering effect */
.skeleton-list-item {
  height: 3px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
  background-image: linear-gradient(90deg, transparent 25%, rgba(255, 255, 255, 0.1) 50%, transparent 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite linear;
}

/* Skeleton variant for loading states */
.skeleton-loading {
  height: 4px;
  border-radius: 2px;
  animation: shimmer 1.5s infinite linear;
}

/* Animation timing functions for natural feel */
@keyframes ease-in-out {
  0% { transform: translateX(-100%) rotate(0deg); }
  50% { transform: translateX(100%) rotate(180deg); }
  100% { transform: translateX(100%) rotate(360deg); }
}

/* Animation duration adjustments */
@keyframes shimmer-fast {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}

.skeleton.fast {
  animation-name: shimmer-fast;
  animation-duration: 0.4s;
}

/* Responsive behavior */
@media (max-width: 600px) {
  .skeleton-text,
  .skeleton-input,
  .skeleton-button,
  .skeleton-card,
  .skeleton-list-item {
    height: 2px;
  }

  .skeleton-fast {
    animation-duration: 0.3s;
  }
}

/* Prevent text-shake effect - use transform instead of translate */
.skeleton-text {
  transform: translateX(-100%) rotate(45deg) scale(0.7);
  background-image: linear-gradient(
    45deg,
    rgba(255, 255, 255, 0) 25%,
    rgba(255, 255, 255, 0.15) 50%,
    rgba(255, 255, 255, 0) 75%
  );
}
