 * Skeleton Component
 * 
 * A reusable skeleton component with shimmer effects, multiple shape variants, and React Suspense integration for lazy loading.
 * 
 * This component provides a visual placeholder that mimics the structure of an interactive element while it is being loaded. It's commonly used in applications to show users what content will appear before it loads, improving perceived performance and reducing user anxiety.
 * 
 * Features:
 * - Multiple shape variants (box, circle, line)
 * - Shimmer animation effect with random delays
 * - React Suspense integration for lazy loading
 * - Responsive design
 * - Customizable styling
 */

import { Fragment } from 'react';
import { Skeleton, Suspense } from 'react';

/**
 * Shape variants available for the skeleton component.
 * Each variant renders a different visual representation of an interactive element.
 */
export const SHAPES = {
  BOX: 'box',
  CIRCLE: 'circle',
  LINE: 'line',
};

const Shape = ({ variant, className }) => {
  switch (variant) {
    case SHAPES.BOX:
      return <div className={className} />;
    case SHAPES.CIRCLE:
