import Skeleton from '../styles/skeleton.css';

/**
 * Skeleton Component - Reusable loading skeleton with shimmer animation
 * 
 * Features:
 * - Multiple shape variants (text, input, button, card, list)
 * - Fast, normal, and slow animation speed variants
 * - React Suspense integration for lazy loading
 * - Scoped CSS to prevent leaks
 */

interface SkeletonProps {
  /** Element type: text | input | button | card | list */
  element?: 'text' | 'input' | 'button' | 'card' | 'list';
  /** Animation speed: fast (0.4s) | normal (1.5s) | slow (3s) */
  speed?: 'fast' | 'normal' | 'slow';
  /** Optional children for text skeleton */
  children?: React.ReactNode;
}

/**
 * Skeleton component with shimmer animation effects
 * @param element - Type of skeleton element
 * @param speed - Animation speed variant
 * @param children - Optional content to display
 */
const Skeleton: React.FC<SkeletonProps> = ({ 
  element, 
  speed = 'normal', 
  children 
}) => {
  const speedClasses = {
    fast: 'fast',
    normal: 'normal',
    slow: 'slow'
  };

  return (
    <div className={`skeleton ${speedClasses[speed]} ${element ? `skeleton-${element}` : ''} ${children ? `skeleton-loading` : ''}`}>
      {children}
    </div>
  );
};

/**
 * SkeletonText component for loading text fields
 */
const SkeletonText: React.FC<{ children?: React.ReactNode }> = ({ children }) => (
  <Skeleton element="text" speed={speed || 'normal'}>{children}</Skeleton>
);

/**
 * SkeletonInput component for loading input fields
 */
const SkeletonInput: React.FC<{ placeholder?: string; required?: boolean }> = ({ 
  placeholder, 
  required 
}) => {
  return (
    <div className="skeleton-input">
      <SkeletonText>{placeholder}</SkeletonText>
      {required && <span className="sr-only" aria-hidden="true">{`required: ${placeholder}`}</span>}
    </div>
  );
};

/**
 * SkeletonButton component for loading buttons
 */
const SkeletonButton: React.FC<{ variant?: 'primary' | 'secondary' | 'outline'; children?: React.ReactNode }> = ({ 
  variant = 'primary',
  children
}) => {
  return (
    <Skeleton element="button" speed={speed || 'normal'}>
      <div className={`skeleton-button ${variant}`}>
        {children}
      </div>
    </Skeleton>
  );
};

/**
 * SkeletonCard component for loading cards
 */
const SkeletonCard: React.FC<{ children?: React.ReactNode }> = ({ children }) => (
  <Skeleton element="card" speed={speed || 'normal'}>
    {children}
  </Skeleton>
);

/**
 * SkeletonList item component for loading list items
 */
const SkeletonListItem: React.FC<{ children?: React.ReactNode }> = ({ children }) => (
  <Skeleton element="list" speed={speed || 'normal'}>
    {children}
  </Skeleton>
);

/**
 * Suspense boundary for lazy loading skeleton components
 * Used to ensure the component is not mounted before data is available
 */
const SkeletonBoundary = ({ children }: { children: React.ReactNode }) => (
  <Suspense fallback={null}>
    {children}
  </Suspense>
);

/**
 * Main Skeleton component wrapper for lazy loading
 * Can be used with Suspense boundaries for additional lazy loading optimization
 */
const SkeletonLoader = ({ element, speed, children }: SkeletonProps) => (
  <SkeletonBoundary>
    <Skeleton element={element} speed={speed} children={children} />
  </SkeletonBoundary>
);

export default Skeleton;

/**
 * Example usage:
 * 
 * ```tsx
 * import { useState } from 'react';
 * import { SkeletonLoader, SkeletonButton, SkeletonCard } from './components/Skeleton';
 * 
 * function MyComponent() {
 *   const [isLoading, setIsLoading] = useState(true);
 *   
 *   if (isLoading) {
 *     return <SkeletonLoader element="card" speed="slow">Loading...</SkeletonLoader>;
 *   }
 *   
 *   return <div>Content</div>;
 * }
 * ```
 */

/**
 * Component with different loading states and skeleton variants
 */
const ExampleSkeleton: React.FC = () => {
  const [activeState, setActiveState] = useState<'text' | 'input' | 'button' | 'card' | 'list'>('text');

  return (
    <div>
      <h2>Skeleton Components with Shimmer Animation</h2>

      <p>Try changing the element type and speed:</p>

      <div className="skeleton-card">
        <SkeletonText>Card Content</SkeletonText>
      </div>

      <div className="skeleton-input">
        <SkeletonText>Input with Placeholder</SkeletonText>
      </div>

      <SkeletonButton variant="primary">
        Action Button
      </SkeletonButton>

      <SkeletonListItem>
        <SkeletonText>List Item 1</SkeletonText>
        <SkeletonText>List Item 2</SkeletonText>
      </SkeletonListItem>
    </div>
  );
};

export default ExampleSkeleton;

/**
 * Component with multiple shape variants and animation speed options
 */
const ShapeVariants: React.FC = () => {
  const shapes = ['text', 'input', 'button', 'card', 'list'];

  return (
    <div className="skeleton-card">
      <h3>Shape Variants with Animation Speed</h3>
      <p>Available variants: text, input, button, card, list</p>
      <p>Animation speeds: fast (0.4s), normal (1.5s), slow (3s)</p>

