 * Skeleton Component with Shimmer Animation
 * 
 * A reusable skeleton component with shimmer effects for loading states.
 * Supports multiple shape variants and proper typing for prop definitions.
 */
import React, { Fragment } from 'react';
import './Skeleton.css';

/**
 * Main Skeleton component with shimmer animation effects.
 * 
 * This component provides a visual placeholder that mimics the structure of an interactive element while it is being loaded.
 * It uses CSS gradients to create shimmer animations without requiring external libraries.
 * 
 * @param {Object} props - Component props
 * @param {string} [props.width='100%'] - Width for grid/shimmer effects (default: '100%')
 * @param {number|string} [props.height='auto'] - Height for line variations (default: 'auto')
 * @param {string} [props.variant='default'] - Visual style: 'grid', 'circle', or 'line' (default: 'grid')
 * @returns {JSX.Element} Rendered skeleton element with shimmer effect
 */
const Skeleton = ({ 
  width = '100%', 
  height = 'auto', 
  variant = 'default' 
}) => {
  const getShimmerStyle = (variant) => {
    switch (variant) {
      case 'grid':
        return {
          background: `
            linear-gradient(90deg, 
              #e5e7eb 1px, transparent 1px),
            linear-gradient(rgba(255, 255, 255, 0.1) 1px, transparent 1px)
          `,
          backgroundSize: `${width} ${width}`,
        };
      case 'circle':
        return {
          background: `
            radial-gradient(
              circle at top left, 
              rgba(255, 255, 255, 0.1) 40%, 
              transparent 60%
            )
          `,
          borderRadius: '50%',
        };
      case 'line':
        return {
          background: `
            linear-gradient(90deg, 
              #e5e7eb ${width}px, 
              transparent ${width}px)
          `,
        };
      default:
        return {
          background: '#e5e7eb',
          borderRadius: '4px',
        };
    }
  };

  const getShape = (variant) => {
    switch (variant) {
      case 'grid':
        return (
          <div className="skeleton-grid" style={getShimmerStyle(variant)}>
            {[...Array(4)].map((_, i) => (
              <div key={i} className="skeleton-row" style={{ width: `${width}%` }} />
            ))}
          </div>
        );
      case 'circle':
        return (
          <div className="skeleton-circle" style={getShimmerStyle(variant)}>
            {[...Array(8)].map((_, i) => (
              <div key={i} className="skeleton-segment" style={{ width: `${Math.random() * 100}%` }} />
            ))}
          </div>
        );
      case 'line':
        return (
          <div className="skeleton-line" style={getShimmerStyle(variant)}>
            {[...Array(3)].map((_, i) => (
              <div key={i} className="skeleton-bar" style={{ height: `${height}px` }} />
            ))}
          </div>
        );
      default:
        return (
          <div className="skeleton-box" style={getShimmerStyle(variant)} />
        );
    }
  };

  return getShape(variant);
};

export default Skeleton;
